        }
        return new BigDecimal(value.toString());
    }

    private BigDecimal divideOrZero(BigDecimal value, long divisor) {
        if (divisor <= 0) {
            return BigDecimal.ZERO;
        }
        return value.divide(BigDecimal.valueOf(divisor), 2, RoundingMode.HALF_UP);
