import React, { useState, useEffect } from 'react';
import { Row, Col, Card, Button, Typography, message, Badge, Modal, List, Tabs, Space } from 'antd';
import { ShoppingCartOutlined, ArrowLeftOutlined, MinusOutlined, PlusOutlined, CloseOutlined } from '@ant-design/icons';
import '../css/FoodMenu.css';
import axios from 'axios';

const { Title, Text } = Typography;
const API_BASE_URL = 'http://localhost:8080/api';

const resolveTableNumberFromUser = () => {
  const fullName = localStorage.getItem('fullName') || '';
  const username = localStorage.getItem('username') || '';
  const source = `${fullName} ${username}`;

  const tableMatch = source.match(/([A-Z]\d{2})/i);
  if (tableMatch?.[1]) {
    const normalized = `Bàn ${tableMatch[1].toUpperCase()}`;
    localStorage.setItem('tableNumber', normalized);
    return normalized;
  }

  const savedTable = localStorage.getItem('tableNumber');
  if (savedTable) {
    return savedTable;
  }

  return 'Bàn A01';
};

const FoodMenu = () => {
  const [tableNumber] = useState(resolveTableNumberFromUser);
  const [menuItems, setMenuItems] = useState([]); // Chứa TẤT CẢ món ăn
  const [filteredItems, setFilteredItems] = useState([]); // Chứa món ăn ĐÃ LỌC theo Tab
  const [categories, setCategories] = useState([]); // Chứa danh sách Tab (Danh mục)

  const [cart, setCart] = useState([]);
  const [isCartModalOpen, setIsCartModalOpen] = useState(false); 
  const [selectedFood, setSelectedFood] = useState(null); 
  const [foodQuantity, setFoodQuantity] = useState(1);
  useEffect(() => {
   // Hàm gọi API lấy Danh mục (Category)
   const fetchCategories = async () => {
      try {
        // API chuẩn: http://localhost:8080/api/foodCategory
        const res = await axios.get(`${API_BASE_URL}/foodCategory`);
        setCategories(res.data.data); 
      } catch (err) {
        console.error(err);
        message.error("Lỗi lấy danh mục!");
      }
    };

      // Hàm gọi API lấy TẤT CẢ món ăn
    const fetchFoods = async () => {
      try {
        // API chuẩn: http://localhost:8080/api/foods/menu
        const res = await axios.get(`${API_BASE_URL}/foods/menu`);
        setMenuItems(res.data.data);
        setFilteredItems(res.data.data); // Mặc định hiển thị tất cả
      } catch (err) {
        console.error(err);
        message.error("Lỗi kết nối Backend!");
      }
    };

    fetchCategories();
    fetchFoods();
  }, []);   // [] có nghĩa là chỉ chạy 1 lần khi Load trang

  // ====================LOGIC LỌC KHI BẤM VÀO TAB ====================
const handleTabChange = (idCategory) => {
    if (idCategory === "ALL") {
      setFilteredItems(menuItems); 
    } else {
      const filtered = menuItems.filter(food => food.idCategory === idCategory);
      setFilteredItems(filtered);
    }
  };

  // ==================== API ĐẶT MÓN  ====================
const handlePlaceOrder = async () => {
    if (cart.length === 0) return message.warning("Giỏ hàng đang trống!");

    const orderPayload = {
      tableNumber,
      customerName: "Khách Lẻ",
      createdBy: "U_001", 
      items: cart.map(item => ({
        foodId: item.idFood,
        quantity: item.quantity
      }))
    };

    try {
      // API chuẩn: http://localhost:8080/api/v1/sales/orders
      await axios.post(`${API_BASE_URL}/v1/sales/orders`, orderPayload);
      message.success("Đặt món thành công! Bếp đang chuẩn bị.");
      setCart([]); 
      setIsCartModalOpen(false); 
    } catch (err) {
      const errorMsg = err.response?.data?.error || "Lỗi đặt món!";
      if (errorMsg.includes("HẾT_HÀNG")) {
         message.error(`Món ${errorMsg.split('|')[1]} đã hết nguyên liệu trong kho!`);
      } else {
         message.error(errorMsg);
      }
    }
  };

  const openFoodDetail = (food) => { setSelectedFood(food); setFoodQuantity(1); };
  const closeFoodDetail = () => { setSelectedFood(null); };

  const handleAddToCart = () => {
    const existingItem = cart.find(item => item.idFood === selectedFood.idFood);
    if (existingItem) {
      setCart(cart.map(item => item.idFood === selectedFood.idFood ? { ...item, quantity: item.quantity + foodQuantity } : item));
    } else {
      setCart([...cart, { ...selectedFood, quantity: foodQuantity }]);
    }
    message.success(`Đã thêm vào giỏ!`);
    closeFoodDetail(); 
  };

  const updateCartQuantity = (foodId, delta) => {
    setCart(cart.map(item => {
      if (item.idFood === foodId) {
        const newQty = item.quantity + delta;
        return { ...item, quantity: newQty > 0 ? newQty : 1 }; 
      }
      return item;
    }));
  };

  const removeFromCart = (foodId) => setCart(cart.filter(item => item.idFood !== foodId));
  const calculateTotal = () => cart.reduce((total, item) => total + (item.unitPrice * item.quantity), 0);
  const getTotalItems = () => cart.reduce((total, item) => total + item.quantity, 0);

  // Ép cái mảng categories (Lấy từ API) thành định dạng Tabs của Ant Design
  const tabItems = [
    { key: 'ALL', label: 'TẤT CẢ' },
    ...categories.map(cat => ({
      key: cat.idCategory, // ID của danh mục làm Khóa
      label: cat.categoryName.toUpperCase() 
    }))
  ];

  return (
    <div>
      {/* 1. HEADER */}
      <div className="header">
        <Badge count={getTotalItems()} offset={[5, 0]}>
          <Button type="text" icon={<ShoppingCartOutlined style={{ fontSize: 28, color: 'white' }} />} onClick={() => setIsCartModalOpen(true)} />
        </Badge>
        <Title level={3} style={{ margin: 0, color: 'white' }}>LOGO</Title>
        <div style={{ display: 'flex', alignItems: 'center', gap: 15 }}>
          <Text strong style={{ fontSize: 16, color: 'white' }}>{tableNumber}</Text>
          <Button type="text" icon={<ArrowLeftOutlined style={{ fontSize: 24, color: 'white' }} />} />
        </div>
      </div>

      <div style={{ padding: '0 20px' }}>
        {/* 2. TABS DANH MỤC */}
        <Tabs 
          defaultActiveKey="ALL" 
          items={tabItems} 
          centered 
          size="large" 
          onChange={handleTabChange} 
        />

        {/* COMBO CON (Vẫn để mock tĩnh tạm thời) */}
        <div style={{ display: 'flex', gap: 10, overflowX: 'auto', paddingBottom: 10, scrollbarWidth: 'none' }}>
          {['combo A', 'combo B', 'combo C'].map(combo => (
             <Button key={combo} shape="round" className="combo-btn" style={{ minWidth: 90 }}>{combo}</Button>
          ))}
        </div>

        <div style={{ background: '#d9d9d9', height: 180, borderRadius: 12, margin: '20px 0', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
          <Text type="secondary" strong>BANNER</Text>
        </div>

        {/* 3. GRID MÓN ĂN */}
        <Row gutter={[16, 16]}>
          {filteredItems.length === 0 ? (
             <div style={{ width: '100%', textAlign: 'center', padding: 50 }}><Text type="secondary">Không có món nào trong danh mục này</Text></div>
          ) : (
            filteredItems.map((food) => (
              <Col xs={12} sm={8} md={8} key={food.idFood}>
                <Card
                  hoverable
                  className="food-card"
                  styles={{ body: { padding: 12, textAlign: 'center', background: '#fff' } }}
                  cover={<div style={{ padding: 10, background: '#f5f5f5' }}>
                     <img alt={food.foodName} src={food.imageUrlFood} style={{ width: '100%', height: 120, objectFit: 'cover', borderRadius: 8 }} />
                  </div>}
                >
                  <Title level={5} style={{ margin: '5px 0' }}>{food.foodName}</Title>
                  <Text type="secondary" style={{ display: 'block', marginBottom: 10 }}>{food.unitPrice.toLocaleString('vi-VN')} đ</Text>

                  <Button 
                    type="primary" shape="round" className="btn-primary-custom" style={{ width: '80%' }} 
                    onClick={() => openFoodDetail(food)}
                    disabled={!food.available}
                  >
                    {food.available ? 'Thêm' : 'Hết món'}
                  </Button>
                </Card>
              </Col>
            ))
          )}
        </Row>
      </div>

      {/* ================= MODAL 1: CHI TIẾT MÓN ĂN ================= */}
      <Modal open={!!selectedFood} onCancel={closeFoodDetail} footer={null} closeIcon={<CloseOutlined style={{ fontSize: 20 }} />} bodyStyle={{ padding: 0 }} width={400}>
        {selectedFood && (
          <div>
            <img src={selectedFood.imageUrlFood} alt={selectedFood.foodName} style={{ width: '100%', height: 250, objectFit: 'cover', borderRadius: '8px 8px 0 0' }} />
            <div style={{ padding: 20 }}>
              <Title level={4} style={{ margin: 0 }}>{selectedFood.foodName}</Title>
              <Text type="secondary">{selectedFood.description}</Text>

              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 30 }}>
                <Space size="middle">
                  <Button shape="circle" icon={<MinusOutlined />} onClick={() => setFoodQuantity(Math.max(1, foodQuantity - 1))} />
                  <Text strong style={{ fontSize: 18 }}>{foodQuantity}</Text>
                  <Button shape="circle" icon={<PlusOutlined />} onClick={() => setFoodQuantity(foodQuantity + 1)} />
                </Space>

                <Button type="primary" shape="round" size="large" className="btn-primary-custom" onClick={handleAddToCart}>
                  Thêm vào giỏ ({(selectedFood.unitPrice * foodQuantity).toLocaleString('vi-VN')} đ)
                </Button>
              </div>
            </div>
          </div>
        )}
      </Modal>

      {/* ================= MODAL 2: GIỎ HÀNG ================= */}
      <Modal title={<Title level={4} style={{ textAlign: 'center', margin: 0 }}>GIỎ HÀNG</Title>} open={isCartModalOpen} onCancel={() => setIsCartModalOpen(false)} footer={null} closeIcon={<CloseOutlined style={{ fontSize: 20 }} />} width={450} bodyStyle={{ background: '#f5f5f5', padding: 10, maxHeight: '60vh', overflowY: 'auto' }}>
        <List
          dataSource={cart}
          renderItem={item => (
            <Card size="small" style={{ marginBottom: 10, borderRadius: 8 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <img src={item.imageUrlFood} alt={item.foodName} style={{ width: 60, height: 60, objectFit: 'cover', borderRadius: 4, marginRight: 10 }} />
                <div style={{ flex: 1 }}>
                  <Text strong>{item.foodName}</Text><br/>
                  <Text type="secondary">{item.unitPrice.toLocaleString('vi-VN')} đ</Text>
                </div>
                <Space>
                  <Button size="small" icon={<MinusOutlined />} onClick={() => updateCartQuantity(item.idFood, -1)} />
                  <Text>{item.quantity}</Text>
                  <Button size="small" icon={<PlusOutlined />} onClick={() => updateCartQuantity(item.idFood, 1)} />
                  <Button size="small" type="text" danger onClick={() => removeFromCart(item.idFood)}>Xóa</Button>
                </Space>
              </div>
            </Card>
          )}
        />

        <div style={{ background: '#fff', padding: 15, borderRadius: 8, marginTop: 10, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Title level={4} type="danger" style={{ margin: 0 }}>Tổng: {calculateTotal().toLocaleString('vi-VN')} đ</Title>
          <Button type="primary" size="large" shape="round" className="btn-primary-custom" onClick={handlePlaceOrder}>
            Đặt món
          </Button>
        </div>
      </Modal>

    </div>
  );
};

export default FoodMenu;

import React, { useState, useEffect } from 'react';
import { Row, Col, Card, Button, Typography, message, Badge, Modal, List, Tabs, Space } from 'antd';
import { ShoppingCartOutlined, ArrowLeftOutlined, MinusOutlined, PlusOutlined, CloseOutlined } from '@ant-design/icons';
import '../css/FoodMenu.css';
import axios from 'axios';

const { Title, Text } = Typography;
const API_BASE_URL = 'http://localhost:8080/api';

const resolveTableNumberFromUser = () => {
  const fullName = localStorage.getItem('fullName') || '';
  const username = localStorage.getItem('username') || '';
  const source = `${fullName} ${username}`;

  const tableMatch = source.match(/([A-Z]\d{2})/i);
  if (tableMatch?.[1]) {
    const normalized = `Bàn ${tableMatch[1].toUpperCase()}`;
    localStorage.setItem('tableNumber', normalized);
    return normalized;
  }

  const savedTable = localStorage.getItem('tableNumber');
  if (savedTable) {
    return savedTable;
  }

  return 'Bàn A01';
};

const toTableCode = (value) => {
  const source = (value || '').toUpperCase().replace('BÀN', '').replace('BAN', '').trim();
  const match = source.match(/[A-Z]\d{2}/);
  return match ? match[0] : 'A01';
};

const FoodMenu = () => {
  const [tableNumber] = useState(resolveTableNumberFromUser);
  const [menuItems, setMenuItems] = useState([]); // Chứa TẤT CẢ món ăn
  const [filteredItems, setFilteredItems] = useState([]); // Chứa món ăn ĐÃ LỌC theo Tab
  const [categories, setCategories] = useState([]); // Chứa danh sách Tab (Danh mục)

  const [cart, setCart] = useState([]);
  const [isCartModalOpen, setIsCartModalOpen] = useState(false); 
  const [selectedFood, setSelectedFood] = useState(null); 
  const [foodQuantity, setFoodQuantity] = useState(1);
  useEffect(() => {
   // Hàm gọi API lấy Danh mục (Category)
   const fetchCategories = async () => {
      try {
        // API chuẩn: http://localhost:8080/api/foodCategory
        const res = await axios.get(`${API_BASE_URL}/foodCategory`);
        setCategories(res.data.data); 
      } catch (err) {
        console.error(err);
        message.error("Lỗi lấy danh mục!");
      }
    };

      // Hàm gọi API lấy TẤT CẢ món ăn
    const fetchFoods = async () => {
      try {
        // API chuẩn: http://localhost:8080/api/foods/menu
        const res = await axios.get(`${API_BASE_URL}/foods/menu`);
        setMenuItems(res.data.data);
        setFilteredItems(res.data.data); // Mặc định hiển thị tất cả
      } catch (err) {
        console.error(err);
        message.error("Lỗi kết nối Backend!");
      }
    };

    fetchCategories();
    fetchFoods();
  }, []);   // [] có nghĩa là chỉ chạy 1 lần khi Load trang

  // ====================LOGIC LỌC KHI BẤM VÀO TAB ====================
const handleTabChange = (idCategory) => {
    if (idCategory === "ALL") {
      setFilteredItems(menuItems); 
    } else {
      const filtered = menuItems.filter(food => food.idCategory === idCategory);
      setFilteredItems(filtered);
    }
  };

  // ==================== API ĐẶT MÓN  ====================
const handlePlaceOrder = async () => {
    if (cart.length === 0) return message.warning("Giỏ hàng đang trống!");

    const orderPayload = {
      tableNumber: toTableCode(tableNumber),
      customerName: "Khách Lẻ",
      createdBy: "U_001", 
      items: cart.map(item => ({
        foodId: item.idFood,
        quantity: item.quantity
      }))
    };

    try {
      // API chuẩn: http://localhost:8080/api/v1/sales/orders
      await axios.post(`${API_BASE_URL}/v1/sales/orders`, orderPayload);
      message.success("Đặt món thành công! Bếp đang chuẩn bị.");
      setCart([]); 
      setIsCartModalOpen(false); 
    } catch (err) {
      const errorMsg = err.response?.data?.error || "Lỗi đặt món!";
      if (errorMsg.includes("HẾT_HÀNG")) {
         message.error(`Món ${errorMsg.split('|')[1]} đã hết nguyên liệu trong kho!`);
      } else {
         message.error(errorMsg);
      }
    }
  };

  const openFoodDetail = (food) => { setSelectedFood(food); setFoodQuantity(1); };
  const closeFoodDetail = () => { setSelectedFood(null); };

  const handleAddToCart = () => {
    const existingItem = cart.find(item => item.idFood === selectedFood.idFood);
    if (existingItem) {
      setCart(cart.map(item => item.idFood === selectedFood.idFood ? { ...item, quantity: item.quantity + foodQuantity } : item));
    } else {
      setCart([...cart, { ...selectedFood, quantity: foodQuantity }]);
    }
    message.success(`Đã thêm vào giỏ!`);
    closeFoodDetail(); 
  };

  const updateCartQuantity = (foodId, delta) => {
    setCart(cart.map(item => {
      if (item.idFood === foodId) {
        const newQty = item.quantity + delta;
        return { ...item, quantity: newQty > 0 ? newQty : 1 }; 
      }
      return item;
    }));
  };

  const removeFromCart = (foodId) => setCart(cart.filter(item => item.idFood !== foodId));
  const calculateTotal = () => cart.reduce((total, item) => total + (item.unitPrice * item.quantity), 0);
  const getTotalItems = () => cart.reduce((total, item) => total + item.quantity, 0);

  // Ép cái mảng categories (Lấy từ API) thành định dạng Tabs của Ant Design
  const tabItems = [
    { key: 'ALL', label: 'TẤT CẢ' },
    ...categories.map(cat => ({
      key: cat.idCategory, // ID của danh mục làm Khóa
      label: cat.categoryName.toUpperCase() 
    }))
  ];

  return (
    <div>
      {/* 1. HEADER */}
      <div className="header">
        <Badge count={getTotalItems()} offset={[5, 0]}>
          <Button type="text" icon={<ShoppingCartOutlined style={{ fontSize: 28, color: 'white' }} />} onClick={() => setIsCartModalOpen(true)} />
        </Badge>
        <Title level={3} style={{ margin: 0, color: 'white' }}>LOGO</Title>
        <div style={{ display: 'flex', alignItems: 'center', gap: 15 }}>
          <Text strong style={{ fontSize: 16, color: 'white' }}>{tableNumber}</Text>
          <Button type="text" icon={<ArrowLeftOutlined style={{ fontSize: 24, color: 'white' }} />} />
        </div>
      </div>

      <div style={{ padding: '0 20px' }}>
        {/* 2. TABS DANH MỤC */}
        <Tabs 
          defaultActiveKey="ALL" 
          items={tabItems} 
          centered 
          size="large" 
          onChange={handleTabChange} 
        />

        {/* COMBO CON (Vẫn để mock tĩnh tạm thời) */}
        <div style={{ display: 'flex', gap: 10, overflowX: 'auto', paddingBottom: 10, scrollbarWidth: 'none' }}>
          {['combo A', 'combo B', 'combo C'].map(combo => (
             <Button key={combo} shape="round" className="combo-btn" style={{ minWidth: 90 }}>{combo}</Button>
          ))}
        </div>

        <div style={{ background: '#d9d9d9', height: 180, borderRadius: 12, margin: '20px 0', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
          <Text type="secondary" strong>BANNER</Text>
        </div>

        {/* 3. GRID MÓN ĂN */}
        <Row gutter={[16, 16]}>
          {filteredItems.length === 0 ? (
             <div style={{ width: '100%', textAlign: 'center', padding: 50 }}><Text type="secondary">Không có món nào trong danh mục này</Text></div>
          ) : (
            filteredItems.map((food) => (
              <Col xs={12} sm={8} md={8} key={food.idFood}>
                <Card
                  hoverable
                  className="food-card"
                  styles={{ body: { padding: 12, textAlign: 'center', background: '#fff' } }}
                  cover={<div style={{ padding: 10, background: '#f5f5f5' }}>
                     <img alt={food.foodName} src={food.imageUrlFood} style={{ width: '100%', height: 120, objectFit: 'cover', borderRadius: 8 }} />
                  </div>}
                >
                  <Title level={5} style={{ margin: '5px 0' }}>{food.foodName}</Title>
                  <Text type="secondary" style={{ display: 'block', marginBottom: 10 }}>{food.unitPrice.toLocaleString('vi-VN')} đ</Text>

                  <Button 
                    type="primary" shape="round" className="btn-primary-custom" style={{ width: '80%' }} 
                    onClick={() => openFoodDetail(food)}
                    disabled={!food.available}
                  >
                    {food.available ? 'Thêm' : 'Hết món'}
                  </Button>
                </Card>
              </Col>
            ))
          )}
        </Row>
      </div>

      {/* ================= MODAL 1: CHI TIẾT MÓN ĂN ================= */}
      <Modal open={!!selectedFood} onCancel={closeFoodDetail} footer={null} closeIcon={<CloseOutlined style={{ fontSize: 20 }} />} bodyStyle={{ padding: 0 }} width={400}>
        {selectedFood && (
          <div>
            <img src={selectedFood.imageUrlFood} alt={selectedFood.foodName} style={{ width: '100%', height: 250, objectFit: 'cover', borderRadius: '8px 8px 0 0' }} />
            <div style={{ padding: 20 }}>
              <Title level={4} style={{ margin: 0 }}>{selectedFood.foodName}</Title>
              <Text type="secondary">{selectedFood.description}</Text>

              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: 30 }}>
                <Space size="middle">
                  <Button shape="circle" icon={<MinusOutlined />} onClick={() => setFoodQuantity(Math.max(1, foodQuantity - 1))} />
                  <Text strong style={{ fontSize: 18 }}>{foodQuantity}</Text>
                  <Button shape="circle" icon={<PlusOutlined />} onClick={() => setFoodQuantity(foodQuantity + 1)} />
                </Space>

                <Button type="primary" shape="round" size="large" className="btn-primary-custom" onClick={handleAddToCart}>
                  Thêm vào giỏ ({(selectedFood.unitPrice * foodQuantity).toLocaleString('vi-VN')} đ)
                </Button>
              </div>
            </div>
          </div>
        )}
      </Modal>

      {/* ================= MODAL 2: GIỎ HÀNG ================= */}
      <Modal title={<Title level={4} style={{ textAlign: 'center', margin: 0 }}>GIỎ HÀNG</Title>} open={isCartModalOpen} onCancel={() => setIsCartModalOpen(false)} footer={null} closeIcon={<CloseOutlined style={{ fontSize: 20 }} />} width={450} bodyStyle={{ background: '#f5f5f5', padding: 10, maxHeight: '60vh', overflowY: 'auto' }}>
        <List
          dataSource={cart}
          renderItem={item => (
            <Card size="small" style={{ marginBottom: 10, borderRadius: 8 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                <img src={item.imageUrlFood} alt={item.foodName} style={{ width: 60, height: 60, objectFit: 'cover', borderRadius: 4, marginRight: 10 }} />
                <div style={{ flex: 1 }}>
                  <Text strong>{item.foodName}</Text><br/>
                  <Text type="secondary">{item.unitPrice.toLocaleString('vi-VN')} đ</Text>
                </div>
                <Space>
                  <Button size="small" icon={<MinusOutlined />} onClick={() => updateCartQuantity(item.idFood, -1)} />
                  <Text>{item.quantity}</Text>
                  <Button size="small" icon={<PlusOutlined />} onClick={() => updateCartQuantity(item.idFood, 1)} />
                  <Button size="small" type="text" danger onClick={() => removeFromCart(item.idFood)}>Xóa</Button>
                </Space>
              </div>
            </Card>
          )}
        />

        <div style={{ background: '#fff', padding: 15, borderRadius: 8, marginTop: 10, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Title level={4} type="danger" style={{ margin: 0 }}>Tổng: {calculateTotal().toLocaleString('vi-VN')} đ</Title>
          <Button type="primary" size="large" shape="round" className="btn-primary-custom" onClick={handlePlaceOrder}>
            Đặt món
          </Button>
        </div>
      </Modal>

    </div>
  );
};

export default FoodMenu;

import React, { useEffect, useMemo, useState } from 'react';
import { message, Empty, Spin } from 'antd';
import axios from 'axios';
import '../css/InventoryPage.css';

const API_BASE_URL = 'http://localhost:8080/api';
const DEFAULT_RECEIPT_STATUS = 'CHO';

const IngredientImage = ({ src, alt }) => {
  const finalSrc = src || '/images/default-food.png';

  return (
    <div className="inventory-image-box">
      <img
        src={finalSrc}
        alt={alt || 'ingredient'}
        className="inventory-real-image"
        onError={(e) => {
          e.currentTarget.src = '/images/default-food.png';
        }}
      />
    </div>
  );
};

const formatMoney = (value) => {
  const number = Number(value || 0);
  return `${number.toLocaleString('vi-VN')} đ`;
};

const formatDateVN = (dateStr) => {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  if (Number.isNaN(date.getTime())) return dateStr;

  return `Ngày ${String(date.getDate()).padStart(2, '0')} Tháng ${String(
    date.getMonth() + 1
  ).padStart(2, '0')} Năm ${date.getFullYear()}`;
};

const normalizeStatus = (status) => {
  const value = (status || '').trim().toUpperCase();

  if (!value) return 'CHO';
  if (['CHO', 'PENDING'].includes(value)) return 'CHO';
  if (['DA_NHAP', 'RECEIVED', 'NHAN_HANG'].includes(value)) return 'DA_NHAP';
  if (['HOAN_TRA', 'RETURNED', 'CANCELLED'].includes(value)) return 'HOAN_TRA';

  return value;
};

const getStatusText = (status) => {
  const normalized = normalizeStatus(status);

  if (normalized === 'CHO') return 'Chờ';
  if (normalized === 'DA_NHAP') return 'Đã nhập';
  if (normalized === 'HOAN_TRA') return 'Hoàn trả';

  return normalized;
};

const isPendingStatus = (status) => normalizeStatus(status) === 'CHO';

function InventoryTrackingTab({ items, loading }) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  if (!items.length) {
    return <Empty description="Chưa có dữ liệu tồn kho" />;
  }

  return (
    <div className="inventory-panel inventory-scroll-area">
      {items.map((item) => (
        <div
          key={item.ingredientId}
          className={`inventory-card ${item.lowStock ? 'inventory-card--warning' : ''}`}
        >
          <IngredientImage
            src={item.imageUrlIngredient}
            alt={item.ingredientName}
          />

          <div className="inventory-card__center">
            <div className="inventory-card__title">{item.ingredientName}</div>
            <div className="inventory-card__sub">Mã nguyên liệu: {item.ingredientId}</div>
            <div className="inventory-card__sub">
              Số lượng tồn: {item.currentStock} {item.unit || ''}
            </div>
            <div className="inventory-card__sub">Mức tối thiểu: {item.minStock}</div>
          </div>

          <div className="inventory-card__right">
            {item.lowStock ? 'Nguyên liệu sắp hết' : 'Tồn kho ổn định'}
          </div>
        </div>
      ))}
    </div>
  );
}

function ImportHistoryTab({
  receipts,
  loading,
  onCreateNew,
  supplierKeyword,
  setSupplierKeyword,
  fromDate,
  setFromDate,
  toDate,
  setToDate,
  ingredientId,
  setIngredientId,
  inventoryItems,
  handleSearch,
  handleReset,
  handleUpdateStatus,
  updatingReceiptId
}) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  return (
    <div className="inventory-scroll-page">
      <div className="inventory-create-title">Lịch sử nhập nguyên liệu</div>

      <div className="inventory-search-box">
        <div className="inventory-search-grid">
          <div className="form-group">
            <label>Nhà cung cấp:</label>
            <input
              value={supplierKeyword}
              onChange={(e) => setSupplierKeyword(e.target.value)}
              placeholder="Nhập tên NCC"
            />
          </div>

          <div className="form-group">
            <label>Từ ngày:</label>
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFromDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Đến ngày:</label>
            <input
              type="date"
              value={toDate}
              onChange={(e) => setToDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Nguyên liệu:</label>
            <select
              value={ingredientId}
              onChange={(e) => setIngredientId(e.target.value)}
            >
              <option value="">-- Tất cả --</option>
              {inventoryItems.map((item) => (
                <option key={item.ingredientId} value={item.ingredientId}>
                  {item.ingredientId} - {item.ingredientName}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div className="inventory-search-actions">
  <button type="button" className="btn btn-primary" onClick={handleSearch}>
    Tìm kiếm
  </button>
  <button type="button" className="btn btn-secondary" onClick={handleReset}>
    Làm mới
  </button>
  <button type="button" className="btn btn-primary" onClick={onCreateNew}>
    Tạo phiếu mới
  </button>
</div>
      </div>

      {!receipts.length ? (
        <Empty description="Chưa có phiếu nhập" />
      ) : (
        receipts.map((receipt) => {
          const totalPrice = (receipt.details || []).reduce((sum, item) => {
            return sum + Number(item.quantityImport || 0) * Number(item.importPrice || 0);
          }, 0);

          const normalizedStatus = normalizeStatus(receipt.status);
          const locked = !isPendingStatus(normalizedStatus);
          const isUpdating = updatingReceiptId === receipt.idReceipt;

          return (
            <div className="receipt-block" key={receipt.idReceipt}>
              <div className="receipt-block__header">
                <span>{receipt.idReceipt} - NCC: {receipt.supplierName || '---'}</span>
                <span>{formatDateVN(receipt.receiptDate)}</span>
              </div>

              <div className="receipt-block__body">
                <div className="receipt-block__items inventory-scroll-area small">
                  {(receipt.details || []).map((item, index) => (
                    <div className="receipt-item" key={`${receipt.idReceipt}-${index}`}>
                      <IngredientImage
                        src={item.imageUrlIngredient}
                        alt={item.ingredientName}
                      />

                      <div className="receipt-item__main">
                        <div className="receipt-item__code">{item.ingredientId}</div>
                        <div className="receipt-item__name">{item.ingredientName}</div>
                      </div>

                      <div className="receipt-item__meta">
                        <div>Số lượng nhập: <span>{item.quantityImport}</span></div>
                        <div>Đơn giá: <span>{formatMoney(item.importPrice)}</span></div>
                        <div>
                          Tổng tiền:{' '}
                          <span>
                            {formatMoney(
                              Number(item.quantityImport || 0) * Number(item.importPrice || 0)
                            )}
                          </span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="receipt-actions">
                  {!locked ? (
                    <>
                      <button
                        type="button"
                        className="btn btn-danger"
                        onClick={() => handleUpdateStatus(receipt, 'HOAN_TRA')}
                        disabled={isUpdating}
                      >
                        {isUpdating ? 'Đang cập nhật...' : 'Hoàn trả'}
                      </button>

                      <button
                        type="button"
                        className="btn btn-success"
                        onClick={() => handleUpdateStatus(receipt, 'DA_NHAP')}
                        disabled={isUpdating}
                      >
                        {isUpdating ? 'Đang cập nhật...' : 'Nhận hàng'}
                      </button>
                    </>
                  ) : (
                    <div className={`status-badge status-badge--${normalizedStatus.toLowerCase()}`}>
                      Trạng thái: {getStatusText(normalizedStatus)}
                    </div>
                  )}

                  <div>Người tạo: {receipt.createdBy || '---'}</div>
                  <div className="receipt-total">Tổng giá: {formatMoney(totalPrice)}</div>
                </div>
              </div>
            </div>
          );
        })
      )}

    </div>
  );
}

function CreateImportTab({ inventoryItems, onBack, onCreated }) {
  const [supplier, setSupplier] = useState('');
  const [date, setDate] = useState('');
  const [createdBy, setCreatedBy] = useState(localStorage.getItem('username') || 'admin');
  const [rows, setRows] = useState([
    { ingredientId: '', quantityImport: 1, importPrice: 0 }
  ]);
  const [submitting, setSubmitting] = useState(false);

  const grandTotal = useMemo(() => {
    return rows.reduce((sum, row) => {
      return sum + Number(row.quantityImport || 0) * Number(row.importPrice || 0);
    }, 0);
  }, [rows]);

  const updateRow = (index, field, value) => {
    const next = [...rows];
    next[index][field] = value;
    setRows(next);
  };

  const addRow = () => {
    setRows([...rows, { ingredientId: '', quantityImport: 1, importPrice: 0 }]);
  };

  const removeRow = () => {
    if (rows.length <= 1) return;
    setRows(rows.slice(0, rows.length - 1));
  };

  const getIngredientInfo = (ingredientId) => {
    return inventoryItems.find((item) => item.ingredientId === ingredientId);
  };

  const handleSubmit = async () => {
    if (!supplier.trim()) {
      message.warning('Vui lòng nhập nhà cung cấp');
      return;
    }

    if (!date) {
      message.warning('Vui lòng chọn ngày lập phiếu');
      return;
    }

    const validRows = rows.filter((row) => row.ingredientId);

    if (!validRows.length) {
      message.warning('Vui lòng chọn ít nhất 1 nguyên liệu');
      return;
    }

    const payload = {
      supplierName: supplier,
      receiptDate: date,
      status: DEFAULT_RECEIPT_STATUS,
      createdBy,
      details: validRows.map((row) => ({
        ingredientId: row.ingredientId,
        quantityImport: Number(row.quantityImport || 0),
        importPrice: Number(row.importPrice || 0)
      }))
    };

    try {
      setSubmitting(true);
      await axios.post(`${API_BASE_URL}/inventory/receipts`, payload);
      message.success('Tạo phiếu nhập thành công');
      onCreated();
    } catch (err) {
      console.error(err);
      message.error(err.response?.data?.message || 'Tạo phiếu nhập thất bại');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="create-receipt-page">
      <div className="create-receipt-header">
        <button type="button" className="back-button" onClick={onBack}>↩</button>
        <div className="inventory-create-title">Tạo phiếu nhập nguyên liệu</div>
      </div>

      <div className="create-receipt-panel">
        <div className="create-top-grid">
          <div className="form-group">
            <label>Nhà cung cấp:</label>
            <input value={supplier} onChange={(e) => setSupplier(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Ngày lập phiếu:</label>
            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Trạng thái:</label>
            <input value="Chờ" readOnly />
          </div>

          <div className="form-group">
            <label>Người tạo:</label>
            <input value={createdBy} onChange={(e) => setCreatedBy(e.target.value)} />
          </div>
        </div>

        <div className="create-list-header">
          <h3>Danh sách nguyên liệu nhập</h3>

          <div className="mini-actions">
            <button type="button" onClick={addRow}>Thêm</button>
            <button type="button" onClick={removeRow}>Xóa</button>
          </div>
        </div>

        <div className="inventory-scroll-area create-list">
          {rows.map((row, index) => {
            const ingredient = getIngredientInfo(row.ingredientId);
            const total = Number(row.quantityImport || 0) * Number(row.importPrice || 0);

            return (
              <div className="create-item" key={index}>
                <IngredientImage
                  src={ingredient?.imageUrlIngredient}
                  alt={ingredient?.ingredientName}
                />

                <div className="create-item__main">
                  <div className="meta-row">
                    <label>Nguyên liệu:</label>
                    <select
                      value={row.ingredientId}
                      onChange={(e) => updateRow(index, 'ingredientId', e.target.value)}
                    >
                      <option value="">-- Chọn nguyên liệu --</option>
                      {inventoryItems.map((item) => (
                        <option key={item.ingredientId} value={item.ingredientId}>
                          {item.ingredientId} - {item.ingredientName}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="create-item__name">
                    {ingredient?.ingredientName || 'Tên nguyên liệu'}
                  </div>

                  <div className="create-item__stock">
                    Số lượng tồn: {ingredient?.currentStock ?? 0} {ingredient?.unit || ''}
                  </div>
                </div>

                <div className="create-item__meta">
                  <div className="meta-row">
                    <label>Số lượng nhập:</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={row.quantityImport}
                      onChange={(e) => updateRow(index, 'quantityImport', e.target.value)}
                    />
                  </div>

                  <div className="meta-row">
                    <label>Đơn giá:</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={row.importPrice}
                      onChange={(e) => updateRow(index, 'importPrice', e.target.value)}
                    />
                  </div>

                  <div className="meta-row">
                    <label>Tổng tiền:</label>
                    <input value={formatMoney(total)} readOnly />
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="create-footer">
          <div className="grand-total">
            <label>Thành tiền:</label>
            <input value={formatMoney(grandTotal)} readOnly />
          </div>

          <button
            type="button"
            className="submit-receipt-btn"
            onClick={handleSubmit}
            disabled={submitting}
          >
            {submitting ? 'Đang gửi...' : 'Gửi phiếu'}
          </button>
        </div>
      </div>
    </div>
  );
}

function ConsumptionHistoryTab({ groups, loading }) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  if (!groups.length) {
    return (
      <div className="inventory-scroll-page">
        <div className="inventory-create-title">Lịch sử tiêu thụ nguyên liệu</div>
        <Empty description="Chưa có dữ liệu tiêu thụ nguyên liệu" />
      </div>
    );
  }

  return (
    <div className="inventory-scroll-page">
      <div className="inventory-create-title">Lịch sử tiêu thụ nguyên liệu</div>

      {groups.map((group, groupIndex) => (
        <div className="receipt-block" key={`${group.date}-${groupIndex}`}>
          <div className="receipt-block__header">
            <span>{formatDateVN(group.date)}</span>
          </div>

          <div className="receipt-block__body">
            <div className="receipt-block__items inventory-scroll-area small">
              {(group.items || []).map((item, index) => (
                <div className="receipt-item" key={`${group.date}-${item.ingredientId}-${index}`}>
                  <IngredientImage
                    src={item.imageUrlIngredient}
                    alt={item.ingredientName}
                  />

                  <div className="receipt-item__main">
                    <div className="receipt-item__code">{item.ingredientId}</div>
                    <div className="receipt-item__name">{item.ingredientName}</div>
                    <div className="inventory-card__sub">
                      Tồn kho hiện tại: {item.currentStock} {item.unit || ''}
                    </div>
                  </div>

                  <div className="receipt-item__meta">
                    <div>
                      Số lượng đã tiêu thụ: <span>{item.consumedQuantity}</span>
                    </div>
                    <div>
                      Đơn vị: <span>{item.unit || '---'}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

export default function InventoryPage() {
  const [mainTab, setMainTab] = useState('tracking');
  const [importMode, setImportMode] = useState('history');

  const [inventoryItems, setInventoryItems] = useState([]);
  const [receipts, setReceipts] = useState([]);
  const [consumptionHistory, setConsumptionHistory] = useState([]);

  const [loadingInventory, setLoadingInventory] = useState(false);
  const [loadingReceipts, setLoadingReceipts] = useState(false);
  const [loadingConsumption, setLoadingConsumption] = useState(false);
  const [updatingReceiptId, setUpdatingReceiptId] = useState('');

  const [supplierKeyword, setSupplierKeyword] = useState('');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');
  const [ingredientId, setIngredientId] = useState('');

  const fetchInventoryReport = async () => {
    try {
      setLoadingInventory(true);
      const res = await axios.get(`${API_BASE_URL}/inventory/report`);
      setInventoryItems(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy dữ liệu tồn kho!');
    } finally {
      setLoadingInventory(false);
    }
  };

  const fetchReceipts = async () => {
    try {
      setLoadingReceipts(true);
      const res = await axios.get(`${API_BASE_URL}/inventory/receipts`);
      setReceipts(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy phiếu nhập!');
    } finally {
      setLoadingReceipts(false);
    }
  };

  const fetchConsumptionHistory = async (fromDateParam, toDateParam) => {
    try {
      setLoadingConsumption(true);
      const params = {};
      if (fromDateParam) params.fromDate = fromDateParam;
      if (toDateParam) params.toDate = toDateParam;

      const res = await axios.get(`${API_BASE_URL}/inventory/consumption-history`, { params });
      setConsumptionHistory(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy lịch sử tiêu thụ nguyên liệu!');
    } finally {
      setLoadingConsumption(false);
    }
  };

  const searchReceipts = async () => {
    try {
      setLoadingReceipts(true);

      const params = {};
      if (supplierKeyword.trim()) params.supplierName = supplierKeyword.trim();
      if (fromDate) params.fromDate = fromDate;
      if (toDate) params.toDate = toDate;
      if (ingredientId) params.ingredientId = ingredientId;

      const res = await axios.get(`${API_BASE_URL}/inventory/receipts/search`, { params });
      setReceipts(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi tìm phiếu nhập!');
    } finally {
      setLoadingReceipts(false);
    }
  };

  const resetSearch = async () => {
    setSupplierKeyword('');
    setFromDate('');
    setToDate('');
    setIngredientId('');
    await fetchReceipts();
  };

  useEffect(() => {
    fetchInventoryReport();
    fetchReceipts();
    fetchConsumptionHistory();
  }, []);

const handleCreated = async () => {
  setImportMode('history');
  await fetchInventoryReport();
  await fetchReceipts();
  await fetchConsumptionHistory();
};

  const handleUpdateStatus = async (receipt, nextStatus) => {
    if (!isPendingStatus(receipt.status)) {
      message.warning('Phiếu này đã cập nhật trạng thái, không thể đổi lại.');
      return;
    }

    const payload = {
      supplierName: receipt.supplierName,
      receiptDate: receipt.receiptDate,
      status: nextStatus,
      createdBy: receipt.createdBy,
      details: (receipt.details || []).map((item) => ({
        ingredientId: item.ingredientId,
        quantityImport: Number(item.quantityImport || 0),
        importPrice: Number(item.importPrice || 0)
      }))
    };

    try {
  setUpdatingReceiptId(receipt.idReceipt);
  await axios.put(`${API_BASE_URL}/inventory/receipts/${receipt.idReceipt}`, payload);
  message.success('Cập nhật trạng thái phiếu thành công');

  await fetchReceipts();
  await fetchInventoryReport();
  await fetchConsumptionHistory();
} catch (err) {
      console.error(err);
      message.error(err.response?.data?.message || 'Cập nhật trạng thái thất bại');
    } finally {
      setUpdatingReceiptId('');
    }
  };

  return (
    <div className="inventory-page">
      <div className="inventory-top-tabs">
        <button
          type="button"
          className={mainTab === 'tracking' ? 'active' : ''}
          onClick={() => setMainTab('tracking')}
        >
          Sổ theo dõi
          <br />
          nguyên liệu
        </button>

        <button
          type="button"
          className={mainTab === 'import' ? 'active' : ''}
          onClick={() => setMainTab('import')}
        >
          Lịch sử nhập
          <br />
          nguyên liệu
        </button>

        <button
          type="button"
          className={mainTab === 'consume' ? 'active' : ''}
          onClick={() => setMainTab('consume')}
        >
          Lịch sử tiêu thụ
          <br />
          nguyên liệu
        </button>
      </div>

      {mainTab === 'tracking' && (
        <InventoryTrackingTab items={inventoryItems} loading={loadingInventory} />
      )}

      {mainTab === 'import' && (
        <>
          {importMode === 'history' ? (
            <ImportHistoryTab
              receipts={receipts}
              loading={loadingReceipts}
              onCreateNew={() => setImportMode('create')}
              supplierKeyword={supplierKeyword}
              setSupplierKeyword={setSupplierKeyword}
              fromDate={fromDate}
              setFromDate={setFromDate}
              toDate={toDate}
              setToDate={setToDate}
              ingredientId={ingredientId}
              setIngredientId={setIngredientId}
              inventoryItems={inventoryItems}
              handleSearch={searchReceipts}
              handleReset={resetSearch}
              handleUpdateStatus={handleUpdateStatus}
              updatingReceiptId={updatingReceiptId}
            />
          ) : (
            <CreateImportTab
              inventoryItems={inventoryItems}
              onBack={() => setImportMode('history')}
              onCreated={handleCreated}
            />
          )}
        </>
      )}

      {mainTab === 'consume' && (
        <ConsumptionHistoryTab
          groups={consumptionHistory}
          loading={loadingConsumption}
        />
      )}
    </div>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { message, Empty, Spin } from 'antd';
import axios from 'axios';
import '../css/InventoryPage.css';

const API_BASE_URL = 'http://localhost:8080/api';
const DEFAULT_RECEIPT_STATUS = 'CHO';

const IngredientImage = ({ src, alt }) => {
  const finalSrc = src || '/images/default-food.png';

  return (
    <div className="inventory-image-box">
      <img
        src={finalSrc}
        alt={alt || 'ingredient'}
        className="inventory-real-image"
        onError={(e) => {
          e.currentTarget.src = '/images/default-food.png';
        }}
      />
    </div>
  );
};

const formatMoney = (value) => {
  const number = Number(value || 0);
  return `${number.toLocaleString('vi-VN')} đ`;
};

const formatDateVN = (dateStr) => {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  if (Number.isNaN(date.getTime())) return dateStr;

  return `Ngày ${String(date.getDate()).padStart(2, '0')} Tháng ${String(
    date.getMonth() + 1
  ).padStart(2, '0')} Năm ${date.getFullYear()}`;
};

const normalizeStatus = (status) => {
  const value = (status || '').trim().toUpperCase();

  if (!value) return 'CHO';
  if (['CHO', 'PENDING'].includes(value)) return 'CHO';
  if (['DA_NHAP', 'RECEIVED', 'NHAN_HANG'].includes(value)) return 'DA_NHAP';
  if (['HOAN_TRA', 'RETURNED', 'CANCELLED'].includes(value)) return 'HOAN_TRA';

  return value;
};

const getStatusText = (status) => {
  const normalized = normalizeStatus(status);

  if (normalized === 'CHO') return 'Chờ';
  if (normalized === 'DA_NHAP') return 'Đã nhập';
  if (normalized === 'HOAN_TRA') return 'Hoàn trả';

  return normalized;
};

const isPendingStatus = (status) => normalizeStatus(status) === 'CHO';

function InventoryTrackingTab({ items, loading }) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  if (!items.length) {
    return <Empty description="Chưa có dữ liệu tồn kho" />;
  }

  return (
    <div className="inventory-panel inventory-scroll-area">
      {items.map((item) => (
        <div
          key={item.ingredientId}
          className={`inventory-card ${item.lowStock ? 'inventory-card--warning' : ''}`}
        >
          <IngredientImage
            src={item.imageUrlIngredient}
            alt={item.ingredientName}
          />

          <div className="inventory-card__center">
            <div className="inventory-card__title">{item.ingredientName}</div>
            <div className="inventory-card__sub">Mã nguyên liệu: {item.ingredientId}</div>
            <div className="inventory-card__sub">
              Số lượng tồn: {item.currentStock} {item.unit || ''}
            </div>
            <div className="inventory-card__sub">Mức tối thiểu: {item.minStock}</div>
          </div>

          <div className="inventory-card__right">
            {item.lowStock ? 'Nguyên liệu sắp hết' : 'Tồn kho ổn định'}
          </div>
        </div>
      ))}
    </div>
  );
}

function ImportHistoryTab({
  receipts,
  loading,
  onCreateNew,
  supplierKeyword,
  setSupplierKeyword,
  fromDate,
  setFromDate,
  toDate,
  setToDate,
  ingredientId,
  setIngredientId,
  inventoryItems,
  handleSearch,
  handleReset,
  handleUpdateStatus,
  updatingReceiptId
}) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  return (
    <div className="inventory-scroll-page">
      <div className="inventory-create-title">Lịch sử nhập nguyên liệu</div>

      <div className="inventory-search-box">
        <div className="inventory-search-grid">
          <div className="form-group">
            <label>Nhà cung cấp:</label>
            <input
              value={supplierKeyword}
              onChange={(e) => setSupplierKeyword(e.target.value)}
              placeholder="Nhập tên NCC"
            />
          </div>

          <div className="form-group">
            <label>Từ ngày:</label>
            <input
              type="date"
              value={fromDate}
              onChange={(e) => setFromDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Đến ngày:</label>
            <input
              type="date"
              value={toDate}
              onChange={(e) => setToDate(e.target.value)}
            />
          </div>

          <div className="form-group">
            <label>Nguyên liệu:</label>
            <select
              value={ingredientId}
              onChange={(e) => setIngredientId(e.target.value)}
            >
              <option value="">-- Tất cả --</option>
              {inventoryItems.map((item) => (
                <option key={item.ingredientId} value={item.ingredientId}>
                  {item.ingredientId} - {item.ingredientName}
                </option>
              ))}
            </select>
          </div>
        </div>

        <div className="inventory-search-actions">
  <button type="button" className="btn btn-primary" onClick={handleSearch}>
    Tìm kiếm
  </button>
  <button type="button" className="btn btn-secondary" onClick={handleReset}>
    Làm mới
  </button>
  <button type="button" className="btn btn-primary" onClick={onCreateNew}>
    Tạo phiếu mới
  </button>
</div>
      </div>

      {!receipts.length ? (
        <Empty description="Chưa có phiếu nhập" />
      ) : (
        receipts.map((receipt) => {
          const totalPrice = (receipt.details || []).reduce((sum, item) => {
            return sum + Number(item.quantityImport || 0) * Number(item.importPrice || 0);
          }, 0);

          const normalizedStatus = normalizeStatus(receipt.status);
          const locked = !isPendingStatus(normalizedStatus);
          const isUpdating = updatingReceiptId === receipt.idReceipt;

          return (
            <div className="receipt-block" key={receipt.idReceipt}>
              <div className="receipt-block__header">
                <span>{receipt.idReceipt} - NCC: {receipt.supplierName || '---'}</span>
                <span>{formatDateVN(receipt.receiptDate)}</span>
              </div>

              <div className="receipt-block__body">
                <div className="receipt-block__items inventory-scroll-area small">
                  {(receipt.details || []).map((item, index) => (
                    <div className="receipt-item" key={`${receipt.idReceipt}-${index}`}>
                      <IngredientImage
                        src={item.imageUrlIngredient}
                        alt={item.ingredientName}
                      />

                      <div className="receipt-item__main">
                        <div className="receipt-item__code">{item.ingredientId}</div>
                        <div className="receipt-item__name">{item.ingredientName}</div>
                      </div>

                      <div className="receipt-item__meta">
                        <div>Số lượng nhập: <span>{item.quantityImport}</span></div>
                        <div>Đơn giá: <span>{formatMoney(item.importPrice)}</span></div>
                        <div>
                          Tổng tiền:{' '}
                          <span>
                            {formatMoney(
                              Number(item.quantityImport || 0) * Number(item.importPrice || 0)
                            )}
                          </span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>

                <div className="receipt-actions">
                  {!locked ? (
                    <>
                      <button
                        type="button"
                        className="btn btn-danger"
                        onClick={() => handleUpdateStatus(receipt, 'HOAN_TRA')}
                        disabled={isUpdating}
                      >
                        {isUpdating ? 'Đang cập nhật...' : 'Hoàn trả'}
                      </button>

                      <button
                        type="button"
                        className="btn btn-success"
                        onClick={() => handleUpdateStatus(receipt, 'DA_NHAP')}
                        disabled={isUpdating}
                      >
                        {isUpdating ? 'Đang cập nhật...' : 'Nhận hàng'}
                      </button>
                    </>
                  ) : (
                    <div className={`status-badge status-badge--${normalizedStatus.toLowerCase()}`}>
                      Trạng thái: {getStatusText(normalizedStatus)}
                    </div>
                  )}

                  <div>Người tạo: {receipt.createdBy || '---'}</div>
                  <div className="receipt-total">Tổng giá: {formatMoney(totalPrice)}</div>
                </div>
              </div>
            </div>
          );
        })
      )}

    </div>
  );
}

function CreateImportTab({ inventoryItems, onBack, onCreated }) {
  const [supplier, setSupplier] = useState('');
  const [date, setDate] = useState('');
  const [createdBy, setCreatedBy] = useState(localStorage.getItem('username') || 'admin');
  const [rows, setRows] = useState([
    { ingredientId: '', quantityImport: 1, importPrice: 0 }
  ]);
  const [submitting, setSubmitting] = useState(false);

  const grandTotal = useMemo(() => {
    return rows.reduce((sum, row) => {
      return sum + Number(row.quantityImport || 0) * Number(row.importPrice || 0);
    }, 0);
  }, [rows]);

  const updateRow = (index, field, value) => {
    const next = [...rows];
    next[index][field] = value;
    setRows(next);
  };

  const addRow = () => {
    setRows([...rows, { ingredientId: '', quantityImport: 1, importPrice: 0 }]);
  };

  const removeRow = () => {
    if (rows.length <= 1) return;
    setRows(rows.slice(0, rows.length - 1));
  };

  const getIngredientInfo = (ingredientId) => {
    return inventoryItems.find((item) => item.ingredientId === ingredientId);
  };

  const handleSubmit = async () => {
    if (!supplier.trim()) {
      message.warning('Vui lòng nhập nhà cung cấp');
      return;
    }

    if (!date) {
      message.warning('Vui lòng chọn ngày lập phiếu');
      return;
    }

    const validRows = rows.filter((row) => row.ingredientId);

    if (!validRows.length) {
      message.warning('Vui lòng chọn ít nhất 1 nguyên liệu');
      return;
    }

    const payload = {
      supplierName: supplier,
      receiptDate: date,
      status: DEFAULT_RECEIPT_STATUS,
      createdBy,
      details: validRows.map((row) => ({
        ingredientId: row.ingredientId,
        quantityImport: Number(row.quantityImport || 0),
        importPrice: Number(row.importPrice || 0)
      }))
    };

    try {
      setSubmitting(true);
      await axios.post(`${API_BASE_URL}/inventory/receipts`, payload);
      message.success('Tạo phiếu nhập thành công');
      onCreated();
    } catch (err) {
      console.error(err);
      message.error(err.response?.data?.message || 'Tạo phiếu nhập thất bại');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="create-receipt-page">
      <div className="create-receipt-header">
        <button type="button" className="back-button" onClick={onBack}>↩</button>
        <div className="inventory-create-title">Tạo phiếu nhập nguyên liệu</div>
      </div>

      <div className="create-receipt-panel">
        <div className="create-top-grid">
          <div className="form-group">
            <label>Nhà cung cấp:</label>
            <input value={supplier} onChange={(e) => setSupplier(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Ngày lập phiếu:</label>
            <input type="date" value={date} onChange={(e) => setDate(e.target.value)} />
          </div>

          <div className="form-group">
            <label>Trạng thái:</label>
            <input value="Chờ" readOnly />
          </div>

          <div className="form-group">
            <label>Người tạo:</label>
            <input value={createdBy} onChange={(e) => setCreatedBy(e.target.value)} />
          </div>
        </div>

        <div className="create-list-header">
          <h3>Danh sách nguyên liệu nhập</h3>

          <div className="mini-actions">
            <button type="button" onClick={addRow}>Thêm</button>
            <button type="button" onClick={removeRow}>Xóa</button>
          </div>
        </div>

        <div className="inventory-scroll-area create-list">
          {rows.map((row, index) => {
            const ingredient = getIngredientInfo(row.ingredientId);
            const total = Number(row.quantityImport || 0) * Number(row.importPrice || 0);

            return (
              <div className="create-item" key={index}>
                <IngredientImage
                  src={ingredient?.imageUrlIngredient}
                  alt={ingredient?.ingredientName}
                />

                <div className="create-item__main">
                  <div className="meta-row">
                    <label>Nguyên liệu:</label>
                    <select
                      value={row.ingredientId}
                      onChange={(e) => updateRow(index, 'ingredientId', e.target.value)}
                    >
                      <option value="">-- Chọn nguyên liệu --</option>
                      {inventoryItems.map((item) => (
                        <option key={item.ingredientId} value={item.ingredientId}>
                          {item.ingredientId} - {item.ingredientName}
                        </option>
                      ))}
                    </select>
                  </div>

                  <div className="create-item__name">
                    {ingredient?.ingredientName || 'Tên nguyên liệu'}
                  </div>

                  <div className="create-item__stock">
                    Số lượng tồn: {ingredient?.currentStock ?? 0} {ingredient?.unit || ''}
                  </div>
                </div>

                <div className="create-item__meta">
                  <div className="meta-row">
                    <label>Số lượng nhập:</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={row.quantityImport}
                      onChange={(e) => updateRow(index, 'quantityImport', e.target.value)}
                    />
                  </div>

                  <div className="meta-row">
                    <label>Đơn giá:</label>
                    <input
                      type="number"
                      min="0"
                      step="0.01"
                      value={row.importPrice}
                      onChange={(e) => updateRow(index, 'importPrice', e.target.value)}
                    />
                  </div>

                  <div className="meta-row">
                    <label>Tổng tiền:</label>
                    <input value={formatMoney(total)} readOnly />
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        <div className="create-footer">
          <div className="grand-total">
            <label>Thành tiền:</label>
            <input value={formatMoney(grandTotal)} readOnly />
          </div>

          <button
            type="button"
            className="submit-receipt-btn"
            onClick={handleSubmit}
            disabled={submitting}
          >
            {submitting ? 'Đang gửi...' : 'Gửi phiếu'}
          </button>
        </div>
      </div>
    </div>
  );
}

function ConsumptionHistoryTab({ groups, loading }) {
  if (loading) {
    return (
      <div className="inventory-loading">
        <Spin size="large" />
      </div>
    );
  }

  if (!groups.length) {
    return (
      <div className="inventory-scroll-page">
        <div className="inventory-create-title">Lịch sử tiêu thụ nguyên liệu</div>
        <Empty description="Chưa có dữ liệu tiêu thụ nguyên liệu" />
      </div>
    );
  }

  return (
    <div className="inventory-scroll-page">
      <div className="inventory-create-title">Lịch sử tiêu thụ nguyên liệu</div>

      {groups.map((group, groupIndex) => (
        <div className="receipt-block" key={`${group.date}-${groupIndex}`}>
          <div className="receipt-block__header">
            <span>{formatDateVN(group.date)}</span>
          </div>

          <div className="receipt-block__body">
            <div className="receipt-block__items inventory-scroll-area small">
              {(group.items || []).map((item, index) => (
                <div className="receipt-item" key={`${group.date}-${item.ingredientId}-${index}`}>
                  <IngredientImage
                    src={item.imageUrlIngredient}
                    alt={item.ingredientName}
                  />

                  <div className="receipt-item__main">
                    <div className="receipt-item__code">{item.ingredientId}</div>
                    <div className="receipt-item__name">{item.ingredientName}</div>
                    <div className="inventory-card__sub">
                      Tồn kho hiện tại: {item.currentStock} {item.unit || ''}
                    </div>
                  </div>

                  <div className="receipt-item__meta">
                    <div>
                      Số lượng đã tiêu thụ: <span>{item.consumedQuantity}</span>
                    </div>
                    <div>
                      Đơn vị: <span>{item.unit || '---'}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}

export default function InventoryPage() {
  const [mainTab, setMainTab] = useState('tracking');
  const [importMode, setImportMode] = useState('history');

  const [inventoryItems, setInventoryItems] = useState([]);
  const [receipts, setReceipts] = useState([]);
  const [consumptionHistory, setConsumptionHistory] = useState([]);

  const [loadingInventory, setLoadingInventory] = useState(false);
  const [loadingReceipts, setLoadingReceipts] = useState(false);
  const [loadingConsumption, setLoadingConsumption] = useState(false);
  const [updatingReceiptId, setUpdatingReceiptId] = useState('');

  const [supplierKeyword, setSupplierKeyword] = useState('');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');
  const [ingredientId, setIngredientId] = useState('');

  const fetchInventoryReport = async () => {
    try {
      setLoadingInventory(true);
      const res = await axios.get(`${API_BASE_URL}/inventory/report`);
      setInventoryItems(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy dữ liệu tồn kho!');
    } finally {
      setLoadingInventory(false);
    }
  };

  const fetchReceipts = async () => {
    try {
      setLoadingReceipts(true);
      const res = await axios.get(`${API_BASE_URL}/inventory/receipts`);
      setReceipts(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy phiếu nhập!');
    } finally {
      setLoadingReceipts(false);
    }
  };

  const fetchConsumptionHistory = async (fromDateParam, toDateParam) => {
    try {
      setLoadingConsumption(true);
      const params = {};
      if (fromDateParam) params.fromDate = fromDateParam;
      if (toDateParam) params.toDate = toDateParam;

      const res = await axios.get(`${API_BASE_URL}/inventory/consumption-history`, { params });
      setConsumptionHistory(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi lấy lịch sử tiêu thụ nguyên liệu!');
    } finally {
      setLoadingConsumption(false);
    }
  };

  const searchReceipts = async () => {
    try {
      setLoadingReceipts(true);

      const params = {};
      if (supplierKeyword.trim()) params.supplierName = supplierKeyword.trim();
      if (fromDate) params.fromDate = fromDate;
      if (toDate) params.toDate = toDate;
      if (ingredientId) params.ingredientId = ingredientId;

      const res = await axios.get(`${API_BASE_URL}/inventory/receipts/search`, { params });
      setReceipts(res.data.data || []);
    } catch (err) {
      console.error(err);
      message.error('Lỗi tìm phiếu nhập!');
    } finally {
      setLoadingReceipts(false);
    }
  };

  const resetSearch = async () => {
    setSupplierKeyword('');
    setFromDate('');
    setToDate('');
    setIngredientId('');
    await fetchReceipts();
  };

  useEffect(() => {
    fetchInventoryReport();
    fetchReceipts();
    fetchConsumptionHistory();
  }, []);

const handleCreated = async () => {
  setImportMode('history');
  await fetchInventoryReport();
  await fetchReceipts();
  await fetchConsumptionHistory();
};

  const handleUpdateStatus = async (receipt, nextStatus) => {
    if (!isPendingStatus(receipt.status)) {
      message.warning('Phiếu này đã cập nhật trạng thái, không thể đổi lại.');
      return;
    }

    const payload = {
      supplierName: receipt.supplierName,
      receiptDate: receipt.receiptDate,
      status: nextStatus,
      createdBy: receipt.createdBy,
      details: (receipt.details || []).map((item) => ({
        ingredientId: item.ingredientId,
        quantityImport: Number(item.quantityImport || 0),
        importPrice: Number(item.importPrice || 0)
      }))
    };

    try {
  setUpdatingReceiptId(receipt.idReceipt);
  await axios.put(`${API_BASE_URL}/inventory/receipts/${receipt.idReceipt}`, payload);
  message.success('Cập nhật trạng thái phiếu thành công');

  await fetchReceipts();
  await fetchInventoryReport();
  await fetchConsumptionHistory();
} catch (err) {
      console.error(err);
      message.error(err.response?.data?.message || 'Cập nhật trạng thái thất bại');
    } finally {
      setUpdatingReceiptId('');
    }
  };

  return (
    <div className="inventory-page">
      <div className="inventory-top-tabs">
        <button
          type="button"
          className={mainTab === 'tracking' ? 'active' : ''}
          onClick={() => setMainTab('tracking')}
        >
          Sổ theo dõi
          <br />
          nguyên liệu
        </button>

        <button
          type="button"
          className={mainTab === 'import' ? 'active' : ''}
          onClick={() => setMainTab('import')}
        >
          Lịch sử nhập
          <br />
          nguyên liệu
        </button>

        <button
          type="button"
          className={mainTab === 'consume' ? 'active' : ''}
          onClick={() => setMainTab('consume')}
        >
          Lịch sử tiêu thụ
          <br />
          nguyên liệu
        </button>
      </div>

      {mainTab === 'tracking' && (
        <InventoryTrackingTab items={inventoryItems} loading={loadingInventory} />
      )}

      {mainTab === 'import' && (
        <>
          {importMode === 'history' ? (
            <ImportHistoryTab
              receipts={receipts}
              loading={loadingReceipts}
              onCreateNew={() => setImportMode('create')}
              supplierKeyword={supplierKeyword}
              setSupplierKeyword={setSupplierKeyword}
              fromDate={fromDate}
              setFromDate={setFromDate}
              toDate={toDate}
              setToDate={setToDate}
              ingredientId={ingredientId}
              setIngredientId={setIngredientId}
              inventoryItems={inventoryItems}
              handleSearch={searchReceipts}
              handleReset={resetSearch}
              handleUpdateStatus={handleUpdateStatus}
              updatingReceiptId={updatingReceiptId}
            />
          ) : (
            <CreateImportTab
              inventoryItems={inventoryItems}
              onBack={() => setImportMode('history')}
              onCreated={handleCreated}
            />
          )}
        </>
      )}

      {mainTab === 'consume' && (
        <ConsumptionHistoryTab
          groups={consumptionHistory}
          loading={loadingConsumption}
        />
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Tabs, Button, Modal, Form, Input, InputNumber, Select, Space, Popconfirm, message, Empty, Spin } from 'antd';
import { PlusOutlined, EditOutlined, DeleteOutlined, MinusCircleOutlined } from '@ant-design/icons';
import axios from 'axios';
import '../css/MenuAdmin.css';

const { Option } = Select;
const { TextArea } = Input;

// Đặt Base URL chuẩn của Backend
const API_BASE_URL = 'http://localhost:8080/api';

const MenuAdmin = () => {
  const [foods, setFoods] = useState([]);
  const [categories, setCategories] = useState([]);
  const [ingredientsList, setIngredientsList] = useState([]);

  const [loading, setLoading] = useState(false); // Trạng thái chờ load data
  const [submitLoading, setSubmitLoading] = useState(false); // Trạng thái chờ nút Lưu

  const [activeTab, setActiveTab] = useState('LH001');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFood, setEditingFood] = useState(null);
  const [form] = Form.useForm();

  // GỌI API LẤY DỮ LIỆU KHI VỪA VÀO TRANG (READ)

  const fetchData = async () => {
    setLoading(true);
    try {
      // Chạy song song 3 API cho nhanh: Danh mục, Nguyên liệu và Món ăn
      const [catRes, ingRes, foodRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/foodCategory`),
        axios.get(`${API_BASE_URL}/ingredient`), // API lấy danh sách kho
        axios.get(`${API_BASE_URL}/foods/menu`)   // API lấy list món ăn
      ]);

      setCategories(catRes.data.data || []);
      setIngredientsList(ingRes.data.data || []);
      setFoods(foodRes.data.data || []);

      // Mặc định chọn Tab đầu tiên nếu có danh mục
      if (catRes.data.data && catRes.data.data.length > 0 && activeTab === 'LH001') {
        setActiveTab(catRes.data.data[0].idCategory);
      }
    } catch (error) {
      console.error("Lỗi lấy dữ liệu:", error);
      message.error("Lỗi kết nối máy chủ! Vui lòng bật Backend.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const filteredFoods = foods.filter(food => food.idCategory === activeTab);

  // Mở Modal (Sửa hoặc Thêm mới)
  const openModal = (food = null) => {
    setEditingFood(food);
    if (food) {
      form.setFieldsValue(food);
    } else {
      form.resetFields();
      form.setFieldsValue({ idCategory: activeTab });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingFood(null);
    form.resetFields();
  };

  // GỌI API THÊM HOẶC SỬA MÓN (CREATE / UPDATE)

  const handleFinish = async (values) => {
    setSubmitLoading(true);
    try {
      if (editingFood) {
        // GỌI API SỬA MÓN (PUT)
        await axios.put(`${API_BASE_URL}/foods/${editingFood.idFood}`, values);
        message.success(`Đã cập nhật món: ${values.foodName}`);
      } else {
        // GỌI API THÊM MỚI (POST)
        await axios.post(`${API_BASE_URL}/foods`, values);
        message.success(`Đã thêm món mới: ${values.foodName}`);
      }

      closeModal();
      fetchData(); // Tải lại danh sách sau khi Lưu thành công

    } catch (error) {
      console.error("Lỗi lưu món ăn:", error);
      message.error(error.response?.data?.message || "Lỗi khi lưu món ăn!");
    } finally {
      setSubmitLoading(false);
    }
  };

  // GỌI API XÓA MÓN (DELETE)
  const handleDelete = async (idFood) => {
    try {
      await axios.delete(`${API_BASE_URL}/foods/${idFood}`);
      message.success(`Đã xóa món ăn thành công!`);
      fetchData(); // Tải lại danh sách
    } catch (error) {
      console.error("Lỗi xóa món ăn:", error);
      message.error("Không thể xóa món này. Có thể nó đang bị dính trong đơn hàng cũ!");
    }
  };

  // Biến mảng categories thành cấu trúc Tabs của Ant Design
  const tabItems = categories.map(cat => ({
    key: cat.idCategory,
    label: cat.categoryName.toUpperCase()
  }));

  return (
    <div className="menu-admin-container">

      {/* HEADER: TABS VÀ NÚT THÊM */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <Tabs 
          className="menu-admin-tabs" 
          activeKey={activeTab} 
          onChange={setActiveTab}
          style={{ flex: 1 }}
          items={tabItems}
        />
        <Button type="primary" icon={<PlusOutlined />} size="large" className="btn-primary-custom" onClick={() => openModal()}>
          Thêm Món
        </Button>
      </div>

      {/* DANH SÁCH MÓN ĂN (CÓ VÒNG QUAY LOADING) */}
      <Spin spinning={loading} tip="Đang tải dữ liệu...">
        <div className="food-list-wrapper">
          {filteredFoods.length === 0 ? (
            <Empty description="Không có món ăn nào trong danh mục này" style={{ marginTop: 50 }} />
          ) : (
            filteredFoods.map(food => (
              <div className="food-list-item" key={food.idFood}>
                <img src={food.imageUrlFood} alt={food.foodName} className="food-image" />

                <div className="food-info">
                  <h3 className="food-title">{food.foodName}</h3>
                  <div className="food-price">Giá: {food.unitPrice.toLocaleString('vi-VN')} đ</div>
                  <div className="food-desc">{food.description}</div>
                </div>

                <div className="food-actions">
                  <Button onClick={() => openModal(food)} icon={<EditOutlined />}>Sửa</Button>
                  <Popconfirm title="Bạn có chắc chắn muốn xóa món này?" onConfirm={() => handleDelete(food.idFood)} okText="Xóa" cancelText="Hủy">
                    <Button danger icon={<DeleteOutlined />}>Xóa</Button>
                  </Popconfirm>
                </div>
              </div>
            ))
          )}
        </div>
      </Spin>

      {/* MODAL THÊM/SỬA MÓN ĂN */}
      <Modal
        title={editingFood ? "Sửa thông tin món ăn" : "Thêm món ăn mới"}
        open={isModalOpen}
        onCancel={closeModal}
        width={700}
        footer={[
          <Button key="cancel" onClick={closeModal}>Hủy</Button>,
          <Button key="submit" type="primary" className="btn-primary-custom" loading={submitLoading} onClick={() => form.submit()}>Lưu lại</Button>
        ]}
      >
        <Form form={form} layout="vertical" onFinish={handleFinish}>
          <div style={{ display: 'flex', gap: '20px' }}>
            <div style={{ flex: 1 }}>
              <Form.Item name="foodName" label="Tên món ăn" rules={[{ required: true, message: 'Vui lòng nhập tên món' }]}>
                <Input placeholder="VD: Hamburger Bò" />
              </Form.Item>

              <Form.Item name="idCategory" label="Danh mục" rules={[{ required: true }]}>
                <Select>
                  {categories.map(cat => (
                    <Option key={cat.idCategory} value={cat.idCategory}>{cat.categoryName}</Option>
                  ))}
                </Select>
              </Form.Item>

              <Form.Item name="unitPrice" label="Đơn giá (VNĐ)" rules={[{ required: true, message: 'Vui lòng nhập giá' }]}>
                <InputNumber style={{ width: '100%' }} formatter={value => `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')} />
              </Form.Item>
            </div>

            <div style={{ flex: 1 }}>
              <Form.Item name="imageUrlFood" label="Đường dẫn ảnh (URL)" rules={[{ required: true, message: 'Vui lòng nhập link ảnh' }]}>
                <Input placeholder="/images/burger.jpg" />
              </Form.Item>

              <Form.Item name="description" label="Mô tả món ăn">
                <TextArea rows={4} placeholder="Nhập mô tả..." />
              </Form.Item>
            </div>
          </div>

          {/* LIST NGUYÊN LIỆU ĐỘNG */}
          <div style={{ marginTop: 10, padding: 15, background: '#f9f9f9', borderRadius: 8, border: '1px solid #e8e8e8' }}>
            <h4 style={{ margin: '0 0 15px 0', color: '#e05252' }}>Định mức nguyên liệu (Recipe)</h4>

            <Form.List name="ingredients">
              {(fields, { add, remove }) => (
                <>
                  {fields.map(({ key, name, ...restField }) => (
                    <Space key={key} style={{ display: 'flex', marginBottom: 8 }} align="baseline">

                      <Form.Item {...restField} name={[name, 'idIngredient']} rules={[{ required: true, message: 'Chọn nguyên liệu' }]}>
                        <Select showSearch placeholder="Chọn nguyên liệu" style={{ width: 300 }}>
                          {ingredientsList.map(ing => (
                            <Option key={ing.idIngredient} value={ing.idIngredient}>{ing.ingredientName} ({ing.unit})</Option>
                          ))}
                        </Select>
                      </Form.Item>

                      <Form.Item {...restField} name={[name, 'quantityUsed']} rules={[{ required: true, message: 'Nhập SL' }]}>
                        <InputNumber placeholder="Số lượng" min={0.01} step={0.01} style={{ width: 120 }} />
                      </Form.Item>

                      <MinusCircleOutlined onClick={() => remove(name)} style={{ color: 'red', fontSize: 18, marginLeft: 10 }} />
                    </Space>
                  ))}
                  <Form.Item>
                    <Button type="dashed" onClick={() => add()} block icon={<PlusOutlined />}>
                      Thêm nguyên liệu cho món này
                    </Button>
                  </Form.Item>
                </>
              )}
            </Form.List>
          </div>

        </Form>
      </Modal>
    </div>
  );
};

export default MenuAdmin;

import React, { useState, useEffect } from 'react';
import { Tabs, Button, Modal, Form, Input, InputNumber, Select, Space, Popconfirm, message, Empty, Spin } from 'antd';
import { PlusOutlined, EditOutlined, DeleteOutlined, MinusCircleOutlined } from '@ant-design/icons';
import axios from 'axios';
import '../css/MenuAdmin.css';

const { Option } = Select;
const { TextArea } = Input;

// Đặt Base URL chuẩn của Backend
const API_BASE_URL = 'http://localhost:8080/api';

const MenuAdmin = () => {
  const [foods, setFoods] = useState([]);
  const [categories, setCategories] = useState([]);
  const [ingredientsList, setIngredientsList] = useState([]);
  const [foodCostsById, setFoodCostsById] = useState({});

  const [loading, setLoading] = useState(false); // Trạng thái chờ load data
  const [submitLoading, setSubmitLoading] = useState(false); // Trạng thái chờ nút Lưu

  const [activeTab, setActiveTab] = useState('LH001');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingFood, setEditingFood] = useState(null);
  const [form] = Form.useForm();

  // GỌI API LẤY DỮ LIỆU KHI VỪA VÀO TRANG (READ)

  const fetchData = async () => {
    setLoading(true);
    try {
      // Chạy song song 3 API chính: Danh mục, Nguyên liệu và Món ăn
      const [catRes, ingRes, foodRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/foodCategory`),
        axios.get(`${API_BASE_URL}/ingredient`), // API lấy danh sách kho
        axios.get(`${API_BASE_URL}/foods/menu`)   // API lấy list món ăn
      ]);

      // API chi phí món là dữ liệu phụ, lỗi thì vẫn cho màn hình menu chạy bình thường.
      let costs = [];
      try {
        const costRes = await axios.get(`${API_BASE_URL}/foods/costs`);
        costs = costRes.data?.data || [];
      } catch (costError) {
        console.warn('Không tải được chi phí món ăn:', costError);
      }

      setCategories(catRes.data.data || []);
      setIngredientsList(ingRes.data.data || []);
      setFoods(foodRes.data.data || []);
      setFoodCostsById(Object.fromEntries(costs.map(item => [item.idFood, item])));

      // Mặc định chọn Tab đầu tiên nếu có danh mục
      if (catRes.data.data && catRes.data.data.length > 0 && activeTab === 'LH001') {
        setActiveTab(catRes.data.data[0].idCategory);
      }
    } catch (error) {
      console.error("Lỗi lấy dữ liệu:", error);
      message.error("Lỗi kết nối máy chủ! Vui lòng bật Backend.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const filteredFoods = foods.filter(food => food.idCategory === activeTab);
  const formatCurrency = (value) => Number(value || 0).toLocaleString('vi-VN');

  // Mở Modal (Sửa hoặc Thêm mới)
  const openModal = (food = null) => {
    setEditingFood(food);
    if (food) {
      form.setFieldsValue(food);
    } else {
      form.resetFields();
      form.setFieldsValue({ idCategory: activeTab });
    }
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setEditingFood(null);
    form.resetFields();
  };

  // GỌI API THÊM HOẶC SỬA MÓN (CREATE / UPDATE)

  const handleFinish = async (values) => {
    setSubmitLoading(true);
    try {
      if (editingFood) {
        // GỌI API SỬA MÓN (PUT)
        await axios.put(`${API_BASE_URL}/foods/${editingFood.idFood}`, values);
        message.success(`Đã cập nhật món: ${values.foodName}`);
      } else {
        // GỌI API THÊM MỚI (POST)
        await axios.post(`${API_BASE_URL}/foods`, values);
        message.success(`Đã thêm món mới: ${values.foodName}`);
      }

      closeModal();
      fetchData(); // Tải lại danh sách sau khi Lưu thành công

    } catch (error) {
      console.error("Lỗi lưu món ăn:", error);
      message.error(error.response?.data?.message || "Lỗi khi lưu món ăn!");
    } finally {
      setSubmitLoading(false);
    }
  };

  // GỌI API XÓA MÓN (DELETE)
  const handleDelete = async (idFood) => {
    try {
      await axios.delete(`${API_BASE_URL}/foods/${idFood}`);
      message.success(`Đã xóa món ăn thành công!`);
      fetchData(); // Tải lại danh sách
    } catch (error) {
      console.error("Lỗi xóa món ăn:", error);
      message.error("Không thể xóa món này. Có thể nó đang bị dính trong đơn hàng cũ!");
    }
  };

  // Biến mảng categories thành cấu trúc Tabs của Ant Design
  const tabItems = categories.map(cat => ({
    key: cat.idCategory,
    label: cat.categoryName.toUpperCase()
  }));

  return (
    <div className="menu-admin-container">

      {/* HEADER: TABS VÀ NÚT THÊM */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <Tabs 
          className="menu-admin-tabs" 
          activeKey={activeTab} 
          onChange={setActiveTab}
          style={{ flex: 1 }}
          items={tabItems}
        />
        <Button type="primary" icon={<PlusOutlined />} size="large" className="btn-primary-custom" onClick={() => openModal()}>
          Thêm Món
        </Button>
      </div>

      {/* DANH SÁCH MÓN ĂN (CÓ VÒNG QUAY LOADING) */}
      <Spin spinning={loading} tip="Đang tải dữ liệu...">
        <div className="food-list-wrapper">
          {filteredFoods.length === 0 ? (
            <Empty description="Không có món ăn nào trong danh mục này" style={{ marginTop: 50 }} />
          ) : (
            filteredFoods.map(food => (
              <div className="food-list-item" key={food.idFood}>
                <img src={food.imageUrlFood} alt={food.foodName} className="food-image" />

                <div className="food-info">
                  {(() => {
                    const costData = foodCostsById[food.idFood];
                    return (
                      <>
                  <h3 className="food-title">{food.foodName}</h3>
                  <div className="food-price">Giá: {food.unitPrice.toLocaleString('vi-VN')} đ</div>
                  <div className="food-desc">{food.description}</div>
                        {costData && (
                          <div className="food-cost-meta">
                            <div>Chi phí: {formatCurrency(costData.productionCost)} đ</div>
                            <div>Lãi gộp: {formatCurrency(costData.grossProfit)} đ</div>
                            <div>Biên lợi nhuận: {Number(costData.marginPercent || 0).toFixed(1)}%</div>
                          </div>
                        )}
                      </>
                    );
                  })()}
                </div>

                <div className="food-actions">
                  <Button onClick={() => openModal(food)} icon={<EditOutlined />}>Sửa</Button>
                  <Popconfirm title="Bạn có chắc chắn muốn xóa món này?" onConfirm={() => handleDelete(food.idFood)} okText="Xóa" cancelText="Hủy">
                    <Button danger icon={<DeleteOutlined />}>Xóa</Button>
                  </Popconfirm>
                </div>
              </div>
            ))
          )}
        </div>
      </Spin>

      {/* MODAL THÊM/SỬA MÓN ĂN */}
      <Modal
        title={editingFood ? "Sửa thông tin món ăn" : "Thêm món ăn mới"}
        open={isModalOpen}
        onCancel={closeModal}
        width={700}
        footer={[
          <Button key="cancel" onClick={closeModal}>Hủy</Button>,
          <Button key="submit" type="primary" className="btn-primary-custom" loading={submitLoading} onClick={() => form.submit()}>Lưu lại</Button>
        ]}
      >
        <Form form={form} layout="vertical" onFinish={handleFinish}>
          <div style={{ display: 'flex', gap: '20px' }}>
            <div style={{ flex: 1 }}>
              <Form.Item name="foodName" label="Tên món ăn" rules={[{ required: true, message: 'Vui lòng nhập tên món' }]}>
                <Input placeholder="VD: Hamburger Bò" />
              </Form.Item>

              <Form.Item name="idCategory" label="Danh mục" rules={[{ required: true }]}>
                <Select>
                  {categories.map(cat => (
                    <Option key={cat.idCategory} value={cat.idCategory}>{cat.categoryName}</Option>
                  ))}
                </Select>
              </Form.Item>

              <Form.Item name="unitPrice" label="Đơn giá (VNĐ)" rules={[{ required: true, message: 'Vui lòng nhập giá' }]}>
                <InputNumber style={{ width: '100%' }} formatter={value => `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ',')} />
              </Form.Item>
            </div>

            <div style={{ flex: 1 }}>
              <Form.Item name="imageUrlFood" label="Đường dẫn ảnh (URL)" rules={[{ required: true, message: 'Vui lòng nhập link ảnh' }]}>
                <Input placeholder="/images/burger.jpg" />
              </Form.Item>

              <Form.Item name="description" label="Mô tả món ăn">
                <TextArea rows={4} placeholder="Nhập mô tả..." />
              </Form.Item>
            </div>
          </div>

          {/* LIST NGUYÊN LIỆU ĐỘNG */}
          <div style={{ marginTop: 10, padding: 15, background: '#f9f9f9', borderRadius: 8, border: '1px solid #e8e8e8' }}>
            <h4 style={{ margin: '0 0 15px 0', color: '#e05252' }}>Định mức nguyên liệu (Recipe)</h4>

            <Form.List name="ingredients">
              {(fields, { add, remove }) => (
                <>
                  {fields.map(({ key, name, ...restField }) => (
                    <Space key={key} style={{ display: 'flex', marginBottom: 8 }} align="baseline">

                      <Form.Item {...restField} name={[name, 'idIngredient']} rules={[{ required: true, message: 'Chọn nguyên liệu' }]}>
                        <Select showSearch placeholder="Chọn nguyên liệu" style={{ width: 300 }}>
                          {ingredientsList.map(ing => (
                            <Option key={ing.idIngredient} value={ing.idIngredient}>{ing.ingredientName} ({ing.unit})</Option>
                          ))}
                        </Select>
                      </Form.Item>

                      <Form.Item {...restField} name={[name, 'quantityUsed']} rules={[{ required: true, message: 'Nhập SL' }]}>
                        <InputNumber placeholder="Số lượng" min={0.01} step={0.01} style={{ width: 120 }} />
                      </Form.Item>

                      <MinusCircleOutlined onClick={() => remove(name)} style={{ color: 'red', fontSize: 18, marginLeft: 10 }} />
                    </Space>
                  ))}
                  <Form.Item>
                    <Button type="dashed" onClick={() => add()} block icon={<PlusOutlined />}>
                      Thêm nguyên liệu cho món này
                    </Button>
                  </Form.Item>
                </>
              )}
            </Form.List>
          </div>

        </Form>
      </Modal>
    </div>
  );
};

export default MenuAdmin;

import React from 'react';

const PaymentPage = () => {
  return (
    <div style={{ padding: 20 }}>
      <h1>Màn hình Thanh Toán</h1>
      <p>Vai trò Thu ngân sẽ thao tác tại đây.</p>
    </div>
  );
};

export default PaymentPage;

import React, { useEffect, useMemo, useState } from 'react';
import { Button, Card, Col, Empty, Input, List, message, Modal, Row, Select, Space, Spin, Tag, Typography } from 'antd';
import apiClient from '../api/apiClient';

const { Title, Text } = Typography;

const PAYMENT_METHOD_OPTIONS = [
  { value: 'CASH', label: 'Tiền mặt' },
  { value: 'TRANSFER', label: 'Chuyển khoản' }
];

const formatCurrency = (value) => `${Number(value || 0).toLocaleString('vi-VN')} đ`;

const PaymentPage = () => {
  const [tables, setTables] = useState([]);
  const [selectedTable, setSelectedTable] = useState('');
  const [orderDetail, setOrderDetail] = useState(null);
  const [loadingTables, setLoadingTables] = useState(false);
  const [loadingOrder, setLoadingOrder] = useState(false);
  const [paying, setPaying] = useState(false);

  const [paymentMethod, setPaymentMethod] = useState('CASH');
  const [customerPhone, setCustomerPhone] = useState('');
  const [isConfirmOpen, setIsConfirmOpen] = useState(false);

  const fetchTables = async () => {
    try {
      setLoadingTables(true);
      const res = await apiClient.get('/v1/sales/tables');
      const nextTables = res.data?.data || [];
      setTables(nextTables);

      if (selectedTable) {
        const selected = nextTables.find((table) => table.tableNumber === selectedTable);
        if (!selected || !selected.unpaid) {
          setOrderDetail(null);
        }
      }
    } catch (error) {
      console.error(error);
      message.error(error.response?.data?.message || 'Không tải được trạng thái bàn');
    } finally {
      setLoadingTables(false);
    }
  };

  const fetchPendingOrder = async (tableNumber) => {
    try {
      setLoadingOrder(true);
      const res = await apiClient.get(`/v1/sales/tables/${tableNumber}/order`);
      setOrderDetail(res.data?.data || null);
    } catch (error) {
      console.error(error);
      setOrderDetail(null);
      message.warning(error.response?.data?.message || 'Bàn này chưa có đơn cần thanh toán');
    } finally {
      setLoadingOrder(false);
    }
  };

  useEffect(() => {
    fetchTables();
  }, [selectedTable]);

  const handleSelectTable = (table) => {
    setSelectedTable(table.tableNumber);
    if (!table.unpaid) {
      setOrderDetail(null);
      message.info(`Bàn ${table.tableNumber} đã thanh toán hoặc chưa có khách.`);
      return;
    }
    fetchPendingOrder(table.tableNumber);
  };

  const totalAmount = useMemo(() => Number(orderDetail?.totalAmount || 0), [orderDetail]);

  const submitPayment = async () => {
    if (!orderDetail?.orderId) {
      message.warning('Vui lòng chọn bàn có đơn chưa thanh toán');
      return;
    }

    try {
      setPaying(true);
      const res = await apiClient.post('/v1/sales/payments', {
        orderId: orderDetail.orderId,
        customerPhone: customerPhone || null,
        paymentMethod
      });

      const invoice = res.data?.data;
      message.success(`Thanh toán thành công. Mã hóa đơn: ${invoice?.invoiceId || ''}`.trim());
      setIsConfirmOpen(false);
      setOrderDetail(null);
      setCustomerPhone('');
      await fetchTables();
    } catch (error) {
      console.error(error);
      message.error(error.response?.data?.message || 'Thanh toán thất bại');
    } finally {
      setPaying(false);
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <Title level={3} style={{ marginBottom: 16 }}>Thanh Toán Thu Ngân</Title>

      <Card title="Trạng thái bàn (Đỏ: chưa thanh toán, Xanh: đã thanh toán)" style={{ marginBottom: 16 }}>
        <Spin spinning={loadingTables}>
          {tables.length === 0 ? (
            <Empty description="Chưa có bàn nào đặt món" />
          ) : (
            <Row gutter={[12, 12]}>
              {tables.map((table) => (
                <Col xs={12} sm={8} md={6} lg={4} key={table.tableNumber}>
                  <Button
                    block
                    style={{
                      height: 52,
                      color: '#fff',
                      border: 'none',
                      background: table.unpaid ? '#ff4d4f' : '#52c41a',
                      boxShadow: selectedTable === table.tableNumber ? '0 0 0 2px rgba(24, 144, 255, 0.35)' : 'none'
                    }}
                    onClick={() => handleSelectTable(table)}
                  >
                    {table.tableNumber}
                  </Button>
                </Col>
              ))}
            </Row>
          )}
        </Spin>
      </Card>

      <Card title={selectedTable ? `Chi tiết bàn ${selectedTable}` : 'Chọn bàn để xem đơn'}>
        <Spin spinning={loadingOrder}>
          {!orderDetail ? (
            <Empty description="Không có đơn chưa thanh toán" />
          ) : (
            <>
              <Space style={{ marginBottom: 12 }}>
                <Tag color="red">Order: {orderDetail.orderId}</Tag>
                <Tag color="blue">Khách: {orderDetail.customerName || 'Khách lẻ'}</Tag>
              </Space>

              <List
                dataSource={orderDetail.items || []}
                renderItem={(item) => (
                  <List.Item>
                    <List.Item.Meta
                      avatar={<img src={item.imageUrlFood} alt={item.foodName} style={{ width: 64, height: 64, objectFit: 'cover', borderRadius: 6 }} />}
                      title={item.foodName}
                      description={`Số lượng: ${item.quantity} | Đơn giá: ${formatCurrency(item.unitPrice)}`}
                    />
                    <Text strong>{formatCurrency(item.lineTotal)}</Text>
                  </List.Item>
                )}
              />

              <div style={{ marginTop: 16, display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 12, flexWrap: 'wrap' }}>
                <Title level={4} type="danger" style={{ margin: 0 }}>
                  Tổng tiền: {formatCurrency(totalAmount)}
                </Title>

                <Space wrap>
                  <Input
                    placeholder="SĐT khách (không bắt buộc)"
                    value={customerPhone}
                    onChange={(e) => setCustomerPhone(e.target.value)}
                    style={{ width: 220 }}
                  />
                  <Select
                    value={paymentMethod}
                    options={PAYMENT_METHOD_OPTIONS}
                    onChange={setPaymentMethod}
                    style={{ width: 180 }}
                  />
                  <Button type="primary" danger disabled={paying || !orderDetail?.orderId} onClick={() => setIsConfirmOpen(true)}>
                    Thanh toán
                  </Button>
                </Space>
              </div>
            </>
          )}
        </Spin>
      </Card>

      <Modal
        title="Xác nhận thanh toán"
        open={isConfirmOpen}
        onCancel={() => setIsConfirmOpen(false)}
        onOk={submitPayment}
        okText={paying ? 'Đang xử lý...' : 'Xác nhận'}
        confirmLoading={paying}
      >
        <p>Bàn: {orderDetail?.tableNumber}</p>
        <p>Mã đơn: {orderDetail?.orderId}</p>
        <p>Hình thức: {PAYMENT_METHOD_OPTIONS.find((m) => m.value === paymentMethod)?.label}</p>
        <p><strong>Tổng tiền: {formatCurrency(totalAmount)}</strong></p>
      </Modal>
    </div>
  );
};

export default PaymentPage;
